phase.icon-css:
/* Add to custom.css */
.sl-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  vertical-align: middle;
  flex-shrink: 0;
}
.sl-icon svg {
  width: 100%;
  height: 100%;
  stroke: currentColor;
  stroke-width: 1.5;
  fill: none;
}
.icon-sm { width: 24px; height: 24px; }
.icon-md { width: 32px; height: 32px; }
.icon-lg { width: 48px; height: 48px; }
.icon-xl { width: 64px; height: 64px; }

/* Override step-icon and tool-icon to work with SVGs */
.flow-step .step-icon {
  font-size: unset; /* remove the emoji font-size */
  display: flex;
  justify-content: center;
  color: var(--accent);
}
.flow-step .step-icon .sl-icon { width: 40px; height: 40px; }
.tool-icon {
  font-size: unset;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent);
}
.tool-icon .sl-icon { width: 32px; height: 32px; }
